INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Important Links & Information', 'important-links-and-information', '<h2>Important Links &amp; Information</h2><p><strong>Official Website</strong><br><a href="https://www.dehumidifiers.com">www.dehumidifiers.com</a></p><p><strong>Calculator App</strong> (perfect for all kinds of psychrometric calculations)<br><a href="https://iatcalc.dehumidifiers.com/CalculatorApp">https://iatcalc.dehumidifiers.com/CalculatorApp</a></p><figure class="img-missing"><figcaption>📷 Image from Trainual: YouTube video — FREE Psychrometric Calculator demo — re-upload via admin editor</figcaption></figure><h3>Marketing Materials</h3><p>At Innovative Air Technologies (IAT), we are committed to providing our Sales Representatives with the tools and resources necessary to excel in their roles. To streamline access to essential digital marketing materials, graphics, and production assets, our Marketing Team has curated a comprehensive Dropbox folder specifically tailored to meet the needs of our sales team.</p><p>This centralized repository serves as a one-stop destination for accessing a wide array of promotional materials and resources designed to support our sales efforts. Within this meticulously organized folder, you will find an extensive collection of high-quality graphics, professional marketing collateral, and multimedia assets to enhance your sales presentations and outreach initiatives.</p><p>To maintain the integrity and consistency of our brand identity across all marketing materials, we kindly remind all Sales Representatives that the resources provided within the Dropbox folder are not to be altered or modified in any way without prior approval from the IAT marketing department.</p><p>In the event that you do not find the specific materials or resources you require within the Dropbox folder, please do not hesitate to reach out to our Marketing Manager Summer Neal.</p><p>Dropbox link: <a href="https://www.dropbox.com/scl/fo/neg8jlfsj7ydy640pqr1h?rlkey=5nee6ylzn679bgb6oidpzold8&amp;dl=0">https://www.dropbox.com/scl/fo/neg8jlfsj7ydy640pqr1h?rlkey=5nee6ylzn679bgb6oidpzold8&amp;dl=0</a></p><p>PW: IATrep</p>', 12, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
