INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'IAT Sales Strategy', 'iat-sales-strategy', '<h2>IAT Sales Strategy</h2><p>At Innovative Air Technologies (IAT), our sales strategy revolves around two primary categories: Design/Build and Plan/Spec. In the Design/Build approach, our focus is on direct sales to owners of companies and buildings. We prioritize understanding the unique needs and requirements of our clients, offering tailored solutions that address their specific challenges and objectives. On the other hand, in the Plan/Spec category, our relationships are cultivated with engineering firms that support owners. Here, we collaborate closely with these firms to ensure our products and solutions can lead to increased consideration in project specifications. By strategically aligning our sales efforts with these two distinct approaches, we aim to maximize opportunities for growth and success while delivering exceptional value to our clients.</p>', 14, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Finding Leads in Your Area', 'finding-leads-in-your-area', '<h2>Finding Leads in Your Area</h2><p>Finding leads in a Sales Representative''s area is crucial for driving business growth and expanding our customer base at Innovative Air Technologies (IAT). Our sales strategy encompasses two distinct approaches: Design/Build and Plan/Spec, each requiring tailored methods for lead generation.</p><h3>1. Design/Build Approach</h3><p>In the Design/Build approach, Sales Representatives focus on direct sales to owners of companies and buildings. To find leads in this area, reps can employ various strategies:</p><ol><li><strong>Networking:</strong> Attend industry events, trade shows, and conferences where building owners and company executives gather. Networking provides opportunities to establish relationships and identify potential leads.</li><li><strong>Cold Outreach:</strong> Utilize cold calling and email campaigns to reach out to target businesses within the rep''s area. Craft personalized messages highlighting the benefits of IAT''s products and services to capture interest.</li><li><strong>Referrals:</strong> Leverage existing client relationships to solicit referrals from satisfied customers. Encourage referrals by offering incentives or discounts for successful leads.</li></ol><h3>2. Plan/Spec Approach</h3><p>For the Plan/Spec category, Sales Representatives build relationships with engineering firms that support owners. Lead generation strategies in this area include:</p><ol><li><strong>Industry Partnerships:</strong> Forge partnerships with engineering firms, architects, and construction companies within the rep''s territory. Collaborate on projects and provide value-added services to establish trust and credibility.</li><li><strong>Educational Workshops/Seminars:</strong> Host educational workshops or seminars targeted toward engineering firms to showcase IAT''s expertise and offerings. Educating these firms about our products and solutions can lead to increased consideration in project specifications.</li><li><strong>Online Presence:</strong> Maintain a strong online presence through platforms like LinkedIn and industry-specific forums. Engage with professionals in the engineering and construction sectors, sharing insights and expertise to position IAT as a trusted resource.</li></ol><p>By employing these targeted lead generation strategies aligned with our Design/Build and Plan/Spec approaches, Sales Representatives can effectively identify and nurture leads within their territories, driving business growth and success for IAT.</p>', 15, TRUE, 4
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Resources', 'resources', '<h2>Resources</h2><h3>Rep Call Sheet</h3><p>A Rep Call Sheet at Innovative Air Technologies (IAT) serves as a vital communication tool for Sales Representatives when our National Sales Manager or IAT President visit their territory. This online form allows reps to document key details, times, and locations of the visit, ensuring seamless coordination and planning. Additionally, the Rep Call Sheet provides an opportunity for reps to highlight any pertinent information that the visiting executives should be aware of, such as key client engagements, ongoing projects, or notable developments within the territory. By diligently completing the Rep Call Sheet, reps facilitate effective communication and ensure that the visiting leadership team is well-prepared and informed for their visit, ultimately contributing to a successful and productive interaction.</p><p>Link: <a href="https://share.jotform.com/241585824241557">https://share.jotform.com/241585824241557</a></p><h3>Company Recommended Resources/Links</h3><ul><li>IAT Q3 Manual</li><li>Dehumidifier walk-thru video: <a href="https://youtu.be/be7hOR-qHb8">https://youtu.be/be7hOR-qHb8</a></li><li>Drybar Blog on our website (Printable PDFs can be found in the Marketing Materials Dropbox folder): <a href="https://www.dehumidifiers.com/blog">https://www.dehumidifiers.com/blog</a></li><li>IAT Case Studies (Printable PDFs can be found in the Marketing Materials Dropbox folder)</li><li>David Schurk ASHRAE Articles (Printable PDFs can be found in the Marketing Materials Dropbox folder)</li></ul><h3>Recommended Associations</h3><ul><li>ASHRAE</li><li>ASHE</li><li>BOMA</li><li>IFMA</li></ul>', 16, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'What is Dryware?', 'what-is-dryware', '<h2>What is Dryware?</h2><p>Innovative Air Technologies'' DryWare software is a comprehensive online quoting tool designed to streamline the process of building industrial desiccant dehumidifiers. This innovative software empowers our team to generate accurate and detailed quotes efficiently, enabling us to meet the unique needs of our clients with precision and speed. One of the standout features of DryWare is its ability to perform real-time calculations and analysis of air properties to optimize the design and performance of our dehumidification solutions. By leveraging DryWare, IAT enhances its ability to deliver tailored and effective solutions for industrial humidity control, ensuring superior performance and customer satisfaction.</p>', 17, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Moisture Load & Heat Calculations', 'moisture-load-and-heat-calculations', '<h2>Moisture Load &amp; Heat Calculations</h2><p>Innovative Air Technologies Technical Advisors offer building moisture and heat load calculations via DryWare software, based on the conditions provided by the Representative, to aid in equipment selection and system design assistance. This service is available on a first come, first serve basis. Our goal is to turn around the calculations within 12–24 hours. Accurate and complete information for the DryWare calculation is critical to turn around time. The information we need to prepare an accurate heat load calculation is contained in the Innovative Air Technologies questionnaire on our website: <a href="https://www.dehumidifiers.com/request-a-quote">www.dehumidifiers.com/request-a-quote</a>.</p><p>The Representative is responsible for verification of the System Conditions upon receipt of load calcs and/or design from Innovative Air Technologies. The Representative must include the System Conditions with all customer quotations when Innovative Air Technologies provides building/room load calculations.</p>', 18, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'System Recommendations & Design', 'system-recommendations-and-design', '<h2>System Recommendations &amp; Design</h2><p>Innovative Air Technologies offers the assistance of recommending the appropriate Innovative Air Technologies dehumidification system layout or design. The Representative must indicate whether the recommendation is to be based on the lowest price or best performance.</p><p>For Innovative Air Technologies to provide an accurate equipment layout a detailed drawing is required that includes notations of building details including door locations, utility locations, obstructions, etc. Ultimately the Representative is responsible for reviewing the final layout for accuracy and feasibility.</p><p>Innovative Air Technologies defines the Sales Process as Influence, Design, Territory and Purchase. Please communicate with your Regional Manager or the Factory prior to quoting any jobs out of your territory with respect to the Sales Process.</p><p>Although Innovative Air Technologies will run the load calculations, suggest a design, and help with equipment and sensor placement, it is the Representatives responsibility to price the equipment for the customer.</p><p>Innovative Air Technologies will offer assistance with pricing and with bid/spec situations at any time. However, the Representative is ultimately responsible for the pricing that is sent to the customer.</p><p>In the case of a new Representative (firm or individual) Innovative Air Technologies will offer special assistance for a predetermined time frame — determined between the Rep and the Region Manager in a written document. Any new manufacturer launch programs will include special incentives or activities agreed to and between Innovative Air Technologies Regional Manager and Representative principal.</p><p>The Representative must include the System Conditions with all customer quotations when Innovative Air Technologies provides building load calculations.</p><p>If Innovative Air Technologies has been specified on a job where more than one Representative is involved, Innovative Air Technologies should be notified in writing in advance of quoting the job to properly communicate to all parties and give credit where credit is due.</p>', 19, TRUE, 4
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Equipment', 'equipment', '<h2>Equipment</h2><p>Innovative Air Technologies ships equipment via common carrier partners selected by Innovative Air Technologies Supply Chain Manager. Every quote through the Innovative Air Technologies DryWare configuration/quote software may contain a freight guide to support Representative quoting activity. Innovative Air Technologies is not responsible for freight or freight costs (unless otherwise noted).</p><p><strong>The following information is required to prepare an accurate freight quote:</strong></p><ul><li>Job name</li><li>Shipping address or zip code</li><li>Unit type</li><li>Quantity</li><li>Accessories</li><li>Total shipping weight</li><li>Shipping Contact</li></ul><p><strong>Shipping Options*:</strong></p><ul><li>Flat bed</li><li>LTL (less than load)</li><li>Specials</li><li>Lift Gate</li></ul><p>*Subject to equipment size, territory and carrier location and availability. Freight quotes are normally only valid for 15 days and cannot be guaranteed until order is scheduled for shipment.</p><p>The representative or customer is welcome to make their own shipping arrangements. The freight dollars on these orders will not be billed through Innovative Air Technologies Inc.; the representative or customer will need to make payment arrangements with the appropriate trucking firm. These orders are considered as &quot;Freight by Customer&quot; — see appropriate section for details.</p>', 20, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Shipping Notes', 'shipping-notes', '<h2>Shipping Notes</h2><ol><li>Innovative Air Technologies Inc. ships all orders FOB Origin unless otherwise agreed to in writing prior to order acceptance. This means that we (the seller) fulfill our obligation to deliver the goods at the time they are placed on the truck at Innovative Air Technologies. In an effort for excellence in Customer Service, Innovative Air Technologies will work with our Reps and customers in order to resolve all freight damage issues (see Freight Damage section).</li><li>Please remember that we specify a planned ship date, which is stated on the acknowledgments, NOT a delivery date. The transit time it takes the product to the customer is the responsibility of the Freight Company. We endeavor to use truck transportation that meets the delivery and quality requirements of our Reps and their customers.</li><li>All Compact Series shipments are made on Common Carrier LTL (less than truckload) unless otherwise requested by Rep/Customer. This means the units will arrive in a closed truck and may go through several terminals prior to arrival on the job site.</li><li>Rotor Series and IDP Series shipments will ship Common Carrier LTL if size allows unless otherwise requested by Rep/Customer. Large units REQUIRE flatbeds and will be shipped accordingly.</li><li>Special arrangements (flat bed, weekend delivery, lift gate, etc.) require a special quote with detailed information. Please note: Rotor and IDP Series shipments on flatbed may require additional packaging or special trucks which will increase the freight costs. Please contact the Factory for additional information.</li><li>Innovative Air Technologies reserves the right to split shipments of large orders as needed to allow for production capacities. Innovative Air Technologies will work with the Rep/Customer to ensure that the schedule is acceptable to the customer requirements and to keep freight changes as low as possible.</li></ol><p>If a purchase order deviates from our standard terms and conditions the factory must approve the purchase order prior to acceptance of the order.</p>', 21, TRUE, 4
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Freight Claim Policy', 'freight-claim-policy', '<h2>Freight Claim Policy</h2><p>Once product leaves Innovative Air Technologies the buyer must bear all costs and risks of loss or damage to the goods, unless shipped Prepaid and Add.</p><p><strong>Receipt of shipment from Innovative Air Technologies should be acknowledged in the following manner:</strong></p><ol><li><strong>Not Damaged and Accept:</strong> Customer agrees shipment has arrived in full and undamaged. This means a freight claim cannot be filed against the freight company. All packaging should be retained until units have been fully inspected — the Freight Company may require inspection of the packaging.</li><li><strong>Damaged and Accept:</strong> Customer agrees shipment has arrived damaged but usable for their application. The customer should note the damage exception on the bill of lading, then immediately contact Innovative Air Technologies for any additional parts needed. A freight claim will need to be filed with coordination between the customer and Innovative Air Technologies.</li><li><strong>Refuse Damaged Freight:</strong> Customer feels the entire unit and/or accessories are damaged to the point that nothing can be used for the application. The damage should be noted on the bill of lading and Innovative Air Technologies Customer Service Group should be contacted immediately. A freight claim should then be filed against the appropriate freight company.</li><li><strong>Missing Component:</strong> If a part is listed on the packing slip but not included in the shipment, the missing component should be noted on the bill of lading before signing. Innovative Air Technologies Customer Service Group should be contacted immediately. Based on shipping paperwork, Innovative Air Technologies Customer Service Group will help determine if the component was missing at the factory or lost in transit and the customer can enter a freight claim, if necessary, to recoup components. Claims must be made within 30 days of receipt of order. Claims made past 30 days will be invoiced to the customer.</li></ol><p>Please do <strong>NOT</strong> return units to Innovative Air Technologies without calling the Factory (770-788-6744) beforehand, or before notifying the freight company of the claim (following their instructions).</p><p>Innovative Air Technologies will do everything possible to expedite the replacement of the unit and/or component. The actual lead-time for replacement will be based upon the part availability, the extent of the damage, and the current production cycle.</p><p>Innovative Air Technologies will not be responsible for the handling or reimbursement on claims with the freight company.</p><p>Upon receipt of damaged freight, an IAT factory tech will inspect the goods and make a determination of repair or replacement. Upon determination, a formal quote will be provided for the replacement/repairs. A purchase order is required to be sent to Innovative Air Technologies for any freight damage repairs or replacement components.</p>', 22, TRUE, 4
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Freight by Customer', 'freight-by-customer', '<h2>Freight by Customer</h2><p>On orders requesting Customer Pick-up (CPU) the following will be the standard procedure:</p><ol><li>When the unit is ready to be picked up, the Factory Shipping Department will contact the Representative via e-mail.</li><li>The Representative will give the customer the Shop Order Number to reference at the time of pick-up. The Representative will also give the customer the pick-up times available at Innovative Air Technologies (8:00 a.m. – 3:00 p.m.). The representative will then contact the Innovative Air Technologies Shipping Department or Sales Support Team with the customer''s expected pick-up date and time.</li><li>The Representative will request the customer call two (2) hours prior to pick-up to ensure the Shipping Department will be ready for CPU.</li><li>If the pick-up is not made within one week of the expected pick-up date and time, the Innovative Air Technologies Shipping Department will contact Order Processing for further direction.</li><li>Order Processing will then contact the Representative again informing him that if the unit is not picked up within 5 working days, storage fees will be assessed beginning on day 6. E-mail will be forwarded to the Shipping Department to let them know the outcome of this contact.</li><li>If the order is still not picked up, storage fees will be assessed through Order Processing and the Representative will be contacted via e-mail a third time and a copy will be sent to the Regional Manager.</li></ol>', 23, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Storage Fees', 'storage-fees', '<h2>Storage Fees</h2><p>Innovative Air Technologies has a very limited capacity to store dehumidification equipment. Consistent with current freight carriers'' fees, a storage charge will be incurred on any order not shipping within five (5) working days of the original acknowledged shipment date. A fee at the daily rate of $50.00 per order will be included with the invoice of the units and denoted as such for orders delayed by customer request.</p><p>To avoid storage fees please notify the Innovative Air Technologies Factory of ship date changes ten (10) working days before acknowledged ship date. Only one ship date change is allowed once production has begun on the order. Units will be held in storage at Innovative Air Technologies a maximum of 30 days. At the end of the 30 days, the order will be cancelled, and a restocking fee will be charged, unless otherwise approved by the Factory (see Restocking section).</p><p>Innovative Air Technologies will notify the Reps weekly regarding impending shipments, missing information required prior to the shipment and possible storage fees. Reps will receive a &quot;Shipment Status&quot; via email from DryWare Rep Portal.</p>', 24, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Order Entry', 'order-entry', '<h2>Order Entry</h2><p>Orders must be submitted with completed order transmittal form and pricing work sheet. Orders cannot be entered until all the equipment rating information is complete and a complete sold-to address is provided.</p><p>Specific information includes:</p><ul><li>Bill To</li><li>Customer Name</li><li>Ship to Address</li><li>Quote uploaded to DryWare Portal</li><li>Sales Submittal uploaded to DryWare Portal</li><li>Voltage</li></ul><p>This information allows Innovative Air Technologies to manufacture and test the equipment to job specifications. Incomplete information, changes or late information will cause delays with submittal packages and ship dates. If possible, the ultimate end username and type of facility should be furnished for future service purposes.</p>', 25, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, '2 Categories of Orders', '2-categories-of-orders', '<h2>2 Categories of Orders</h2><p>All orders placed with Innovative Air Technologies fall into one of two categories:</p><ol><li><strong>Released for Production</strong></li><li><strong>Hold for Approval Order</strong></li></ol>', 26, TRUE, 1
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Released for Production', 'released-for-production', '<h2>Released for Production</h2><p>It is the Representative''s responsibility to provide accurate and complete ship-to information and a verified Purchase Order (PO) from the customer to Innovative Air Technologies for release of order. A signed quote is acceptable in lieu of a PO. The document must contain the correct price for the Innovative Air Technologies equipment, the customer''s reference number (if required) and the customer''s signature. No order will be manufactured without a PO from the customer on file at Innovative Air Technologies. Orders received without a PO will be placed on hold for production until the PO is received. Planned ship dates will be assigned based on current lead times at time of release. If special consideration is required on an order, the request MUST be noted when the order is placed or discussed with the Order Processing Coordinator.</p><p>An Order Acknowledgement will be sent within (1) one week of receipt of orders unless order requires special pricing or special parts. (Further covered in Acknowledgement Step.) Submittals will be provided within 2 weeks of order entry. (Further covered in Submittals Step.)</p>', 27, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Hold for Approval Order', 'hold-for-approval-order', '<h2>Hold for Approval Order</h2><p>This is an order that will NOT be scheduled for production. Innovative Air Technologies will issue a submittal package confirming the information on Hold for Approval Orders within (1) one week unless order requires special pricing or special parts. Once approved specs and PO are received, the order will become a Released for Production Order. An official PO can be used as a formal approval, but &quot;ok to release&quot; must be stated on the document.</p><p>On the Order Transmittal cover page please fill out the Section of the form. The Rep is also responsible for supplying a Tax-Exempt Certificate from the customer where required.</p><p>Please note: If an order is received that includes additional parts for OTHER Innovative Air Technologies service products, the parts portion of the order will be forwarded to the Innovative Air Technologies Service Group for entry, shipping, and invoicing. See Parts Orders for more information.</p>', 28, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Third Party Supplied Components', 'third-party-supplied-components', '<h2>Third Party Supplied Components</h2><p>In cases where the order includes parts and/or components supplied by a third party, Innovative Air Technologies Inc. will not schedule the unit(s) for build until an e-mail is received confirming the delivery of the third-party supplied item(s).</p><p>If for any reason there is a delay in the receipt of the third-party item(s), Innovative Air Technologies, Inc. will not be responsible for any delay in the shipment of the unit(s).</p>', 29, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Buy/Resell', 'buy-resell', '<h2>Buy/Resell</h2><p>Innovative Air Technologies allows buy/resell by Representatives to contractors or end users basic formal written approvals from the Innovative Air Technologies Regional Manager. Reps are to submit a Buy/Resell approval form for review and approval by the Innovative Air Technologies Regional Manager.</p>', 30, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Acknowledgements', 'acknowledgements', '<h2>Acknowledgements</h2><p>Acknowledgements are emailed out weekly. To ensure the order has been entered correctly, acknowledgements are sent out on &quot;Released for Production&quot; orders to the customer and Representative. Representatives participating in commission splits (if applicable) will receive the Detailed Order Acknowledgement. The customer will receive the Summary Acknowledgement, along with a copy of the Terms and Conditions. (See Section 9.) Incomplete information or changes will delay the sending of acknowledgements.</p><p>All Reps are responsible for reviewing acknowledgements for accuracy of:</p><ul><li>Order date</li><li>Order components</li><li>Planned ship date</li><li>Ship-to and Sold-to information</li><li>Commission splits, if applicable</li></ul><p><strong>Innovative Air Technologies should be notified immediately of any errors found during the review.</strong></p>', 31, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Submittals', 'submittals', '<h2>Submittals</h2><p>Submittals should be reviewed for accuracy by the Rep prior to delivery to the customer. A submittal is a final check to make sure everything on the order is accurate. Innovative Air Technologies should be notified immediately of any errors found during the review. For quicker turn around, please contact Sales Support Team.</p><p>Submittals are generally provided within 2 weeks of order acknowledgement. Submittals include equipment description(s), cut sheets, and electrical connection diagrams. Submittals are now available through the Innovative Air Technologies DryWare Portal. After receiving the submittals from Innovative Air Technologies, the Representative is responsible for obtaining the Purchase Order is responsible for delivering copies to the customer, if required.</p>', 32, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Change Order', 'change-order', '<h2>Change Order</h2><p>If a change is made to an order, whether it is Released for Production or Hold for Approval, it must be submitted in writing to the factory. No verbal changes will be accepted. The Representative is responsible for verifying all information before order is accepted to avoid errors. Please take time to read the acknowledgements as well as the submittals. New submittals will not be sent on Change Orders unless requested at the time the change is sent in. The Representative is responsible for requesting a new submittal if required.</p><p>Change orders may affect price. If a change causes an adjustment in price, a new purchase order must be submitted from the customer. It is the Representative''s responsibility to make sure that this paperwork is submitted prior to shipment.</p><p>Change orders may affect the planned ship date — be sure to consult the Sales Support Team.</p><p><strong>Changes made to Orders In Production:</strong> If a change is made to the unit after it is already in production, changes will apply for actual time and materials necessary to make the change. Rework to the unit may affect the planned ship date.</p><p>See the Return Unit Procedure for units returned for rework.</p>', 33, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Restocking', 'restocking', '<h2>Restocking</h2><p>A restocking fee will be charged on any orders cancelled after production has begun. Consult the Factory for rates. (NOTE: Restocking charges are higher on special requests and IDP Series due to the custom nature of these products.) Restocking fees may range from 25% – 75% of the final cost of the equipment (basis: standard or custom design).</p><p>Commissions will not be paid on restocking fees. These fees are to recover the cost of manufacture of the unit(s) only.</p><p>If the units have been shipped — see the Return Units procedure.</p><p>There are four types of returns:</p><ol><li>Cancelled units</li><li>Customer modification request</li><li>Modification due to error in manufacture</li><li>Return parts from original order</li></ol><p>The Representative is responsible for communication to Order Processing when an item is to be returned to Innovative Air Technologies. The Representative and customer should work out the details of the return shipment. Innovative Air Technologies can assist in arranging truck transportation, if necessary, but it is ultimately the Rep and/or Customer responsibility.</p><p>Restocking fees will apply to all cancelled units and returned parts. Rework charges may apply to any return depending on the request.</p><p>The Representative or Customer is responsible for taking pictures of the units prior to their departure. To avoid rework charges due to damage in transit it is important for these pictures to be taken and sent to the Innovative Air Technologies Customer Service Group.</p><p>Once the unit is received at Innovative Air Technologies and evaluated for requested modification and/or damage, a final estimate of restocking fees, rework fees and freight costs will be determined and communicated to the Representative.</p><p>At no time is commission paid on cancelled units, returned parts, or rework fees.</p>', 34, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Credit Problems', 'credit-problems', '<h2>Credit Problems</h2><p>When a customer is determined to be on a &quot;cash in advance&quot; status due to previous payment problems, the following procedure will be followed:</p><ol><li>Upon receipt of the order, Innovative Air Technologies Order Processing Representative or Accounting Manager will contact the Sales Representative with a payment agreement (see attached).</li><li>The order will be placed on hold until that payment agreement is signed by the customer and returned to Innovative Air Technologies.</li><li>Once the payment agreement is received, Innovative Air Technologies will release the unit for production; however, the shipment will not be released until the payment agreement terms are met.</li><li>Once Innovative Air Technologies receives payment, as per the payment agreement, the order will be cleared to be released for shipment.</li><li>If no payment is made, the shipment will be held for 30 days past the original shipment date. On day 31, Innovative Air Technologies will assume that the order has been cancelled and an invoicing for the standard restocking fee plus appropriate storage fees will be sent to the customer for immediate payment.</li></ol><p>Innovative Air Technologies will be responsible for contacting the Rep with the appropriate correspondence. The Rep will be responsible for contacting the customer and ensuring that the payment agreement is signed and returned to Innovative Air Technologies as soon as possible. The Rep will also be responsible for follow-up contact with the customer in the case where payment is late, or a cancellation/re-stocking situation occurs.</p>', 35, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
