-- ── Lessons: How we Use Trainual at IAT ──
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'What is Trainual?', 'what-is-trainual', '<h2>What is Trainual?</h2><p><strong>Welcome to Trainual</strong></p><p>Our business thrives on <strong>repeatable processes</strong>. They are incredibly important in ensuring that we maintain world class quality and consistency in everything we do. The consistency we achieve through these processes is what drives our business growth, benefiting everyone involved!</p><p>To make all of this possible, we recognized the need for a central hub to document these processes. That&apos;s where Trainual comes in. <em><strong>Think of it as the playbook for our business, a comprehensive guide for everything we do here.</strong></em></p><figure class="img-missing"><figcaption>📷 Image from Trainual: GIF of Dwight Schrute from The Office saying &quot;Let&apos;s do this!&quot; — re-upload via admin editor</figcaption></figure><p><em>Next, we&apos;ll go over the expectations for using Trainual at Innovative Air Technologies.</em></p>', 0, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'how-we-use-trainual-at-iat'
