INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Expectations', 'expectations', '<h2>Expectations</h2><p>We&apos;ve invested a lot of time, effort, money, a little bit of sweat (Summer may have cried a few tears) to build our playbook.</p><p>Our goal is for Trainual to be the <strong><em>ONE</em></strong> source of truth for <strong><em>EVERYTHING</em></strong> we do at IAT. No more tribal knowledge.</p><p>If it&apos;s in Kacy&apos;s brain, it will be on Trainual (<em>eventually</em>).</p><figure class="img-missing"><figcaption>📷 Image from Trainual: GIF with caption &quot;The age of chaos is over!&quot; — re-upload via admin editor</figcaption></figure><p><strong>Now, there are 2 things we need YOU to do:</strong></p><h3>1. Check Trainual FIRST!</h3><p>If you have a question about any part of our business or your job, look it up in Trainual first. It&apos;s super easy! Just use the <strong>Search</strong> tool on the top of the page to ask questions and find your answers.</p><h3>2. If it&apos;s not in Trainual, let us know!</h3><p>If you can&apos;t find the answers you&apos;re looking for in Trainual, let your manager know. First, so they can answer your question. And second, so they can make sure it gets documented in Trainual.</p><p><em>Next, we&apos;ll cover a few other features and tools for using Trainual.</em></p>', 1, TRUE, 4
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'how-we-use-trainual-at-iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Trainual University', 'trainual-university', '<h2>Trainual University</h2><figure class="img-missing"><figcaption>📷 Image from Trainual: Trainual University logo/badge — re-upload via admin editor</figcaption></figure><p>Trainual University is where you&apos;ll learn how to use Trainual&apos;s program features. Trainual University is optional but <em><strong>highly recommended.</strong></em></p><h3>This will include:</h3><ol><li>A short subject to show you how to use Trainual U.</li><li>A Trainual orientation course designed just for you and how you&apos;ll be using Trainual.</li></ol><h3>How to access Trainual U</h3><p>Click the card on your Home page or click your avatar menu and select <strong>Go to Trainual U</strong>. This will open Trainual U in a new tab in your browser.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Screenshot of the Trainual avatar dropdown menu showing &quot;Go to Trainual U&quot; option — re-upload via admin editor</figcaption></figure>', 2, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'how-we-use-trainual-at-iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Download the App', 'download-the-app', '<h2>Download the App</h2><p>Trainual! There&apos;s an app for that.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Trainual app icon (purple with &quot;T&quot;) — re-upload via admin editor</figcaption></figure><p>With the app, you can easily search, view, complete, and access your assigned content anytime, anywhere, right on your phone or tablet!</p><p><strong>Click below to download the correct version.</strong></p><ul><li><a href="https://play.google.com/store/apps/details?id=com.trainual.trainual">Get it on Google Play</a></li><li><a href="https://apps.apple.com/app/trainual/id1477396049">Download on the App Store</a></li></ul>', 3, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'how-we-use-trainual-at-iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'If you need help with Trainual', 'if-you-need-help-with-trainual', '<h2>If you need help with Trainual</h2><p>Our <strong>ONSITE</strong> Trainual Expert is:</p><p><strong>Summer Neal</strong><br><a href="mailto:summer@dehumidifiers.com">summer@dehumidifiers.com</a></p><p>Send an email or just stop by her office, you could use the walk and she needs human interaction.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: GIF with caption &quot;Come on!&quot; (humorous encouragement to reach out) — re-upload via admin editor</figcaption></figure>', 4, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'how-we-use-trainual-at-iat'
ON CONFLICT (module_id, slug) DO NOTHING;
